class Solution {
public:
    unordered_map<string, string> map;
    string encode(string longUrl) {
        string key = to_string(map.size());
        map[key] = longUrl;
        return "http://tinyurl.com/" + key;
    }

    string decode(string shortUrl) {
        size_t pos = shortUrl.find("http://tinyurl.com/");
        string key = shortUrl.substr(pos + 19);
        return map[key];
    }
};
